var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"오늘은 우리는 특별한 소망을 위해 이 자리에 모였습니다.","JPN":"今日私たちは、特別な願いのためにここに集まりました。","ENG":"Today, we have gathered here for a special wish.","TWN":"今天，我們為了特別的願望聚集於此。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"세계의 종말 이후, 다신 없을 평온한 삶을 낙원이란 이름으로 대가 없이 베풀었던 황금나무는...","JPN":"世界の終末後、二度とない穏やかな暮らしを楽園という名のもとに無償で与えてくれた黄金の木は……","ENG":"The Golden Tree, which granted us the peaceful life called the Promised Land after the end of the world without asking anything in return...","TWN":"在世界末日後，以樂園之名，無私奉獻再也不會擁有的和平生活的黃金樹……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"지금 외적으로부터 그 존재를 위협 받고 있습니다.","JPN":"今、外部からその存在を脅かされています。","ENG":"is now being threatened from the outside.","TWN":"如今正受到外部的威脅。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러니 여러분께선 부디...","JPN":"ですから皆さんはどうか……","ENG":"So I ask that you all...","TWN":"因此請各位……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"오늘 하루, 우리의 소망을 위해서가 아닌 황금나무를 위해 기도를 올려주셨으면 합니다.","JPN":"今日1日は、私たちの願いではなく黄金の木のために祈りを捧げてください。","ENG":"Today, offer your prayers not for your own wishes, but for the Golden Tree.","TWN":"今天這一天，不是為了我們的願望，而是為了黃金樹祈禱。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"걱정마십시오, 사제님. 낙원을 위해 저의 소망을 바치겠습니다.","JPN":"心配には及びません、司祭様。楽園のために私の願いを捧げます。","ENG":"Don't worry, Father. I will offer my wish for the sake of the Promised Land.","TWN":"請放心，司祭。我願將我的願望奉獻給樂園。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAN_ANAP_NULL_NULL","text":{"KOREA":"비록 찰나였으나 우리 모두 해가 저물며 밤이 도래하는 광경을 똑똑히 보았습니다, 사제님. 그것은 예언의 때가 도래했단 뜻이죠.","JPN":"私たちは皆、一瞬でしたが日が暮れて夜が到来する景色をこの目で見ました、司祭様。それはついに予言の時が来たということなのでしょう。","ENG":"Though it was only for a moment, we all clearly witnessed the sun set and night fall, Father. That means the time of prophecy has come.","TWN":"雖然只是片刻，但我們都清楚地看見了日落與夜晚降臨，司祭。那正是預言之時到來的證明。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"암군 타기리온이 가져왔던 종말의 비극을 한시도 잊은 적 없답니다. 그걸 막기 위해서라면 소망 뿐만 아니라 제 목숨도 바치겠어요.","JPN":"暗君タギリオンがもたらした終末の悲劇を、一瞬たりとも忘れたことはありません。それを止められるなら、願いだけでなくこの命も捧げます。","ENG":"I have never forgotten, not even for a moment, the tragedy of the end that the Ignorant Monarch Thagirion brought. If it's to stop that, I would offer not only my wish but even my life.","TWN":"我從未忘記暗君塔基里翁帶來的末日悲劇。為了阻止它，不只是願望，我願意連性命都奉上。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WOMAN_ANAP_NULL_NULL","text":{"KOREA":"저도 마찬가지에요.","JPN":"私もです。","ENG":"As do I.","TWN":"我也是。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리는 사상도, 이념도, 태어나 살아온 시기도 달랐으나, 공동의 소망을 품고 있습니다.","JPN":"私たちは思想も、理念も、生きた時代も異なりますが、共通の願いを抱いています。","ENG":"Though our beliefs, ideals, and the times we were born and lived in are all different, we share a common wish.","TWN":"我們的思想、理念、出生與時代都不同，但我們擁有共同的願望。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그것은, 암군 타기리온으로부터 더 이상 누구도 고통 받지 않는 세계... 완전한 낙원, 아나필리스를 완성하는 것.","JPN":"それはこれ以上誰も暗君タギリオンに苦しめられない世界……完全なる楽園、アナピリスを完成すること。","ENG":"That wish is to complete a world where no one suffers any longer because of the Ignorant Monarch Thagirion... The perfect Promised Land, Anapilis.","TWN":"那就是不再讓任何人因暗君塔基里翁而痛苦的世界……完成真正的樂園，阿納菲莉絲。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"이제 그 예언의 실현이 머지 않았으니...","JPN":"そしてその予言の実現は目前に来ています……","ENG":"Now that the fulfillment of that prophecy is near...","TWN":"如今預言的實現已近在眼前……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...다 함께 기도합시다.","JPN":"……皆さん共に、祈りを捧げましょう。","ENG":"...Let us all pray together.","TWN":"……讓我們一同祈禱吧。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"무슨... 소리지?","JPN":"何の……音？","ENG":"What... is that sound?","TWN":"什麼……聲音？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"방금 전까지만 해도 고통스러웠는데... 지금은 따스한 기운이 온몸을 감싸고 있어.","JPN":"さっきまで苦しかったのに……今は温かい気配に全身を包まれている。","ENG":"Just a moment ago I was in pain... but now a warm presence is wrapping around my whole body.","TWN":"剛才明明還很痛苦……現在全身卻被溫暖的氣息包圍。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"깨어나셨군요, 늑대 씨.","JPN":"起きたんですね、オオカミさん。","ENG":"You've awakened, Wolf.","TWN":"你醒了，狼。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...넌? 누구지?","JPN":"……あなたは？　誰？","ENG":"...You? Who are you?","TWN":"……你是？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"제 이름은 아우드라. 당신을 이곳에서 아주 오랫동안 기다렸죠.","JPN":"私の名前はアウドラ。とても長い間、ここであなたを待っていました。","ENG":"My name is Audra. I've been waiting for you here for a very long time.","TWN":"我的名字是奧德拉，我已在這裡等你很久了。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"날... 기다리고 있었다고?","JPN":"私を……待っていた？","ENG":"You've... been waiting for me?","TWN":"等……我？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"난 분명 마왕 타기리온을 막으려고... 왔는데...","JPN":"私は確か魔王タギリオンを食い止めに……来たはずだけど……","ENG":"I definitely came here... to stop the Demon Lord Thagirion...","TWN":"我明明是為了阻止魔王塔基里翁……才來的……"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"여긴 대체 어디지?","JPN":"ここはどこ？","ENG":"Where exactly is this place?","TWN":"這裡到底是哪裡？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이곳은 낙원.","JPN":"ここは楽園。","ENG":"This is the Promised Land.","TWN":"這裡是樂園。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신들이 다다르고 싶어했던, 설산의 꼭대기이자, 타기리온의 옥좌가 있는 곳이기도 하죠.","JPN":"あなたたちが目指していた雪山の頂上であり、タギリオンの玉座がある場所でもあります。","ENG":"The summit of the snowy mountain you were trying to reach... and the place where Thagirion's throne lies as well.","TWN":"也是你們想抵達的雪山山頂，同時也是塔基里翁王座所在地。"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...뭐?","JPN":"……え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"FLOOR_FACILITY_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아이들이 뛰어 놀고 있어.","JPN":"子どもたちが駆け回ってる。","ENG":"Children are running around.","TWN":"孩子們在奔跑玩耍。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하늘은 푸르고, 새소리도 들리는데.","JPN":"空は青く、鳥のさえずりも聞こえる。","ENG":"The sky is blue, and I can hear birds singing.","TWN":"天空湛藍，還聽得到鳥鳴。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이게 정말... 한 차례 멸망을 겪었던 세계란 거야?","JPN":"本当にここが……一度滅びを経験した世界だって言うの？","ENG":"Is this really... a world that already faced destruction once?","TWN":"這真的是……曾經毀滅過一次的世界嗎？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이건 누군가의 아름다운 추억이 소망으로 구현된 풍경일 뿐이에요.","JPN":"これは誰かの美しい思い出が願いとして具現化した景色にすぎません。","ENG":"This is only a landscape shaped from someone's beautiful memories made manifest through a wish.","TWN":"這只是某人的美好回憶，以願望具現化的景象而已。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"죽은 사람들은 지난 과거를 추억 할 뿐, 새로운 기억은 만들어내지 못하거든요.","JPN":"死んだ人は過去の思い出を振り返ることはできても、新しい記憶を生み出すことはできませんから。","ENG":"The dead can only recall the past they once lived. They can't create new memories.","TWN":"因為死去的人只能回憶過去，無法創造新的記憶。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};